import assert from "node:assert/strict";
import test from "node:test";

import { readMessages } from "../src/messageReader.ts";

test("mixed line endings and packet cuts decode as one complete stream", () => {
  const bytes = new TextEncoder().encode(
    '{"label":"caf\u00e9"}\r\n{"label":"go \u{1F680}"}',
  );
  const chunks = [
    bytes.slice(0, 15),
    bytes.slice(15, 16),
    new Uint8Array(),
    bytes.slice(16, 35),
    bytes.slice(35, 37),
    bytes.slice(37),
  ];

  assert.deepEqual(readMessages(chunks), [
    { label: "caf\u00e9" },
    { label: "go \u{1F680}" },
  ]);
});
